    #[test]
    fn test_solo_magnitude_ratio_calibration() {
        // Measure per-step magnitude ratio from the evolution equation directly.
        // Uses a kernel with epsilon_mag_relative = 1000 (effectively disabled)
        // to let K advance, then measures the actual ratios.
        let dim = 3; let m = 1;
        let anchor = canonical_anchor(dim, m);
        let ops = operators::production_operators_3x3();
        let mut params = SaiosParams::default_register();
        params.epsilon_mag_relative = qr(1000, 1); // effectively disabled
        let kernel = SaiosKernel::new(params, ops);
        let mut state = EntityState {
            entity_id: 0, k_index: 0, sluice_state: SluiceState::Locked,
            latest_sigma_enc: 0, delta_k: anchor.clone(), delta_bar: anchor,
            trajectory: Trajectory::new(), t_k_latest: QR::zero(),
        };
        let mut max_ratio = QR::zero();
        let mut advances = 0u64;
        for tick in 0..100u64 {
            let mag_before = phi_norm_sq_delta(&state.delta_k);
            match kernel.execute_k_step(&mut state) {
                Ok(_) => {
                    advances += 1;
                    let mag_after = phi_norm_sq_delta(&state.delta_k);
                    if !mag_before.is_zero() {
                        let diff = if mag_after >= mag_before {
                            &mag_after - &mag_before
                        } else {
                            &mag_before - &mag_after
                        };
                        let ratio = &diff / &mag_before;
                        let approx = ratio.numer().to_string().parse::<f64>().unwrap_or(0.0)
                            / ratio.denom().to_string().parse::<f64>().unwrap_or(1.0);
                        if tick < 20 {
                            eprintln!("  tick {:3}: ratio = {:.8}", tick, approx);
                        }
                        if ratio > max_ratio { max_ratio = ratio.clone(); }
                    }
                }
                Err(_) => {}
            }
        }
        let max_approx = max_ratio.numer().to_string().parse::<f64>().unwrap_or(0.0)
            / max_ratio.denom().to_string().parse::<f64>().unwrap_or(1.0);
        eprintln!("Advances: {}/100", advances);
        eprintln!("Max ratio: {:.8}", max_approx);
        eprintln!("Recommended: max * 1.2 = {:.8}", max_approx * 1.2);
        // The max ratio determines the correct epsilon_mag_relative
        assert!(advances > 0, "No K advances even with disabled magnitude check");
    }

